const token = $input.first().headers['x-carbonsense-token'];
if (!token || token !== $env.CARBONSENSE_SHARED_SECRET) {
  throw new Error('Unauthorized');
}

const b = $input.first().json.body || $input.first().json;
if (typeof b.rating !== 'number' || b.rating < 1 || b.rating > 5) {
  throw new Error('rating must be an integer 1..5');
}
if (!b.anon_id) {
  // Belt-and-braces: derive anon_id here if Django didn't send one. Django
  // already computes it, but if a client calls this webhook directly we
  // still want consistent anonymity.
  const crypto = require('crypto');
  const today = new Date().toISOString().slice(0, 10);
  const salt = ($env.FEEDBACK_DAILY_SALT_PREFIX || 'cs-anon') + today;
  const ip = ($input.first().headers['x-forwarded-for'] || '').split(',')[0].trim() || 'unknown';
  const ua = $input.first().headers['user-agent'] || 'unknown';
  b.anon_id = crypto.createHash('sha256').update(`${ip}|${ua}|${salt}`).digest('hex').slice(0, 32);
}

return [{ json: {
  run_id: b.run_id || null,
  rating: b.rating,
  feedback_text: b.feedback_text || '',
  helpful_action_indices: Array.isArray(b.helpful_action_indices) ? b.helpful_action_indices : [],
  unhelpful_action_indices: Array.isArray(b.unhelpful_action_indices) ? b.unhelpful_action_indices : [],
  anon_id: b.anon_id,
  area_id: b.area_id || null,
  sector: b.sector || null,
}}];

